using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class UserMilestoneConfiguration : IEntityTypeConfiguration<UserMilestone>{public void Configure(EntityTypeBuilder<UserMilestone> builder){builder.ToTable("user_milestones");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("milestone_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.MilestoneType).HasMaxLength(50).IsRequired();builder.Property(e => e.MilestoneValue).HasColumnType("decimal(8,2)");builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasIndex(e => new { e.UserId, e.MilestoneType });}}
